1	import { createLogger, PluginError, type Logger, type Plugin } from '@ax/core';
2	import { Kysely, PostgresDialect } from 'kysely';
3	import pg from 'pg';
4	
5	/**
6	 * @ax/database-postgres — owns the pg.Pool + Kysely instance for the
7	 * postgres-backed plugin family (storage-postgres, session-postgres, ...).
8	 *
9	 * Exposes a single service hook:
10	 *
11	 *   database:get-instance(ctx, {}) -> { db: Kysely<unknown> }
12	 *
13	 * Singleton semantics: every caller gets the same Kysely instance backed by
14	 * the same pg.Pool. Plugins that need a typed schema cast the returned
15	 * `db` to their own `Kysely<MySchema>` at the edge — the kernel-level type
16	 * stays generic so we don't leak any one plugin's table shape into the
17	 * shared contract.
18	 *
19	 * Why a separate plugin owns the pool:
20	 * - One source of truth (Invariant 4) — only one place opens connections.
21	 * - Storage / session / audit each have their own table prefix and
22	 *   migrations, but share the pool to avoid N pools per process.
23	 *
24	 * Why eventbus-postgres does NOT use this: LISTEN requires a dedicated,
25	 * non-pooled client held open for the lifetime of the subscription. Pool
26	 * connections can be returned mid-listen, breaking subscriptions. So
27	 * eventbus-postgres takes its own connectionString and opens a single
28	 * pg.Client. (See its plugin.ts for the deep-dive.)
29	 */
30	
31	const PLUGIN_NAME = '@ax/database-postgres';
32	
33	export interface DatabasePostgresConfig {
34	  connectionString: string;
35	  poolMax?: number;
36	  /**
37	   * Optional logger for background pg.Pool errors (idle-pool socket failures,
38	   * e.g., postgres restart in k8s). Defaults to a stdout JSON logger tagged
39	   * `reqId=database-postgres-bg`. Without a listener attached, an unhandled
40	   * 'error' from the pool would crash the process.
41	   */
42	  logger?: Logger;
43	}
44	
45	export interface DatabaseGetInstanceOutput {
46	  db: Kysely<unknown>;
47	}
48	
49	export function createDatabasePostgresPlugin(config: DatabasePostgresConfig): Plugin {
50	  let kysely: Kysely<unknown> | undefined;
51	
52	  return {
53	    manifest: {
54	      name: PLUGIN_NAME,
55	      version: '0.0.0',
56	      registers: ['database:get-instance'],
57	      calls: [],
58	      subscribes: [],
59	    },
60	    // TODO(kernel-shutdown): destroy the pool on shutdown when the kernel
61	    // gains a plugin shutdown lifecycle. Today the process exits before
62	    // anything can close; pg cleans up its own sockets via Node teardown.
63	    init({ bus }) {
64	      validateConnectionString(config.connectionString);
65	      const bgLogger =
66	        config.logger ?? createLogger({ reqId: 'database-postgres-bg' });
67	
68	      const pool = new pg.Pool({
69	        connectionString: config.connectionString,
70	        max: config.poolMax ?? 10,
71	      });
72	      // pg.Pool emits 'error' for idle-pool socket failures (e.g., postgres
73	      // restart). Without a listener Node treats it as unhandled and crashes
74	      // the process — exactly the failure mode this pool sits idle waiting
75	      // for between requests.
76	      pool.on('error', (err) => {
77	        bgLogger.error('database_postgres_pool_error', {
78	          err: err instanceof Error ? err : new Error(String(err)),
79	        });
80	      });
81	      kysely = new Kysely<unknown>({
82	        dialect: new PostgresDialect({ pool }),
83	      });
84	
85	      bus.registerService<unknown, DatabaseGetInstanceOutput>(
86	        'database:get-instance',
87	        PLUGIN_NAME,
88	        async () => ({ db: kysely! }),
89	      );
90	    },
91	  };
92	}
93	
94	function validateConnectionString(connectionString: unknown): void {
95	  if (typeof connectionString !== 'string' || connectionString.length === 0) {
96	    throw new PluginError({
97	      code: 'invalid-config',
98	      plugin: PLUGIN_NAME,
99	      message: `${PLUGIN_NAME}: connectionString must be a non-empty string`,
100	    });
101	  }
102	  if (!/^postgres(ql)?:\/\//.test(connectionString)) {
103	    throw new PluginError({
104	      code: 'invalid-config',
105	      plugin: PLUGIN_NAME,
106	      message: `${PLUGIN_NAME}: connectionString must start with postgres:// or postgresql://`,
107	    });
