24	//   mid-listen, breaking the binding. So we open both a pg.Pool (for
25	//   queries) and a pg.Client (for LISTEN) directly, side-by-side, against
26	//   the same connectionString. The eventbus-postgres plugin set this
27	//   precedent — we follow it intentionally for the same reason.
28	//
29	//   This is an INTENTIONAL bypass of the database hook. Any postgres
30	//   plugin that needs LISTEN follows the same shape.
31	//
32	// Hook contract: identical to @ax/session-inmemory. The contract tests
33	// in `src/__tests__/plugin.test.ts` exercise the same surface; if both
34	// plugins ever drift, those tests are the canary.
35	//
36	// Cross-replica wakeup: `session:queue-work` fires `pg_notify` on a
37	// per-session channel; `session:claim-work` blocks on LISTEN of the same
38	// channel. So a queue on instance A wakes a claim on instance B against
39	// the same database.
40	// ---------------------------------------------------------------------------
41	
42	const PLUGIN_NAME = '@ax/session-postgres';
43	
