49	   * idle errors, LISTEN client socket errors, init failure cleanup. Defaults
50	   * to a stdout JSON logger tagged `reqId=session-postgres-bg`. Tests can
51	   * pass a noop or recording logger.
52	   */
53	  logger?: Logger;
54	}
55	
