2	import { createRequire } from 'node:module';
3	import { pathToFileURL } from 'node:url';
4	import {
5	  HookBus,
6	  bootstrap,
7	  makeChatContext,
8	  type ChatOutcome,
9	  type Plugin,
10	} from '@ax/core';
11	import { llmMockPlugin } from '@ax/llm-mock';
12	import { createLlmAnthropicPlugin } from '@ax/llm-anthropic';
13	import { createStorageSqlitePlugin } from '@ax/storage-sqlite';
14	import { createCredentialsPlugin } from '@ax/credentials';
15	import { auditLogPlugin } from '@ax/audit-log';
16	import { createSandboxSubprocessPlugin } from '@ax/sandbox-subprocess';
17	import { createSessionInmemoryPlugin } from '@ax/session-inmemory';
18	import { createIpcServerPlugin } from '@ax/ipc-server';
19	import { createLlmProxyAnthropicFormatPlugin } from '@ax/llm-proxy-anthropic-format';
20	import { createChatOrchestratorPlugin } from '@ax/chat-orchestrator';
21	import { createToolDispatcherPlugin } from '@ax/tool-dispatcher';
22	import { createToolBashPlugin } from '@ax/tool-bash';
23	import { createToolFileIoPlugin } from '@ax/tool-file-io';
24	import { createMcpClientPlugin } from '@ax/mcp-client';
25	import { AxConfigSchema, type AxConfig, type AxConfigInput } from './config/schema.js';
26	import { loadAxConfig } from './config/load.js';
27	import { runCredentialsCommand } from './commands/credentials.js';
28	import { runMcpCommand } from './commands/mcp.js';
29	import { runServeCommand } from './commands/serve.js';
30	
31	// `@ax/cli` is the ONE package permitted to import sibling plugins directly
32	// (eslint.config.mjs no-restricted-imports allowlist); this is also the one
33	// spot where we pin down the runner binary location (I8).
34	//
35	// Lazy-resolve the agent-native-runner binary inside main() rather than at
36	// module load. Library-mode consumers (tests, embedders using configOverride)
37	// that never invoke chat:run shouldn't fail to import @ax/cli just because
38	// the runner's dist/ hasn't been built yet. `createRequire` from the CLI's
39	// own URL is robust against pnpm hoisting and works identically in dev + prod.
40	//
41	// We resolve the package's `.` export (which is `dist/main.js`) rather than
42	// a subpath specifier: the runner's `exports` field only exposes `.` and
43	// `./turn-loop`, so a direct `./dist/main.js` subpath is blocked by Node's
44	// exports-map enforcement.
45	const requireFromCli = createRequire(import.meta.url);
46	export function resolveRunnerBinary(runner: AxConfig['runner']): string {
47	  // Exhaustive so a future `runner` variant in schema.ts fails typecheck
48	  // here instead of silently falling through to the native runner.
49	  switch (runner) {
50	    case 'claude-sdk':
51	      return requireFromCli.resolve('@ax/agent-claude-sdk-runner');
52	    case 'native':
53	      return requireFromCli.resolve('@ax/agent-native-runner');
54	    default: {
55	      const _exhaustive: never = runner;
56	      throw new Error(`unknown runner: ${String(_exhaustive)}`);
57	    }
58	  }
59	}
60	const DEFAULT_CHAT_TIMEOUT_MS = 10 * 60_000;
61	
62	export interface MainOptions {
63	  message: string;
64	  /**
65	   * Library-mode config override. When set, we skip file discovery entirely
66	   * — the override is parsed (to apply defaults) and used as-is. This is the
67	   * seam tests and embedders use to avoid touching disk.
68	   */
69	  configOverride?: AxConfigInput;
70	  /** Directory to walk for `ax.config.*`. Defaults to `process.cwd()`. */
71	  cwd?: string;
72	  /**
73	   * Override the sqlite DB path from config. Exists to keep legacy `AX_DB`
74	   * env-var binary-mode working while we phase config-driven storage in.
75	   */
76	  sqlitePath?: string;
77	  /**
78	   * Override `ChatContext.workspace.rootPath`. Defaults to `cwd`, which in
79	   * turn defaults to `process.cwd()`. Tool sandboxes land inside this dir.
80	   */
81	  workspaceRoot?: string;
82	  stdout?: (line: string) => void;
83	  stderr?: (line: string) => void;
84	  /**
85	   * Test-seam ONLY. When set and `cfg.llm === 'anthropic'`, replaces the real
86	   * SDK client with the factory result — same hatch the llm-anthropic plugin
87	   * already exposes, threaded through here for library-mode tests. Lives on
88	   * `MainOptions` (not in the JSON config schema) because functions aren't
89	   * JSON-serializable and this seam must not be reachable from file-based
90	   * config. Not used in binary-mode.
91	   */
92	  anthropicClientFactory?: (apiKey: string) => {
93	    messages: { create(req: Record<string, unknown>): Promise<unknown> };
94	  };
95	  /**
96	   * Test-seam ONLY. Extra plugins appended AFTER the config-driven plugin
97	   * set, before bootstrap. Lets library-mode tests inject observer plugins
98	   * (e.g. a `tool:post-call` subscriber that records events) and stub
99	   * service registrations (see `skipDefaultLlm`). Not reachable from
100	   * file-based config — plugins aren't JSON-serializable.
101	   */
102	  extraPlugins?: Plugin[];
103	  /**
104	   * Test-seam ONLY. When true, the default LLM plugin selected by
105	   * `cfg.llm` is NOT pushed — callers must supply an `llm:call` registrar
106	   * through `extraPlugins`. Exists because the hook bus enforces exactly
107	   * one registrar per service hook, so "override the default" means "don't
108	   * register the default". Not reachable from file-based config.
109	   */
110	  skipDefaultLlm?: boolean;
111	}
112	
113	const DEFAULT_SQLITE_PATH = './ax-next-chat.sqlite';
114	
115	export async function main(opts: MainOptions): Promise<number> {
116	  const out = opts.stdout ?? ((line) => process.stdout.write(line + '\n'));
117	  const err = opts.stderr ?? ((line) => process.stderr.write(line + '\n'));
118	
119	  const cwd = opts.cwd ?? process.cwd();
120	  const cfg: AxConfig =
121	    opts.configOverride !== undefined
122	      ? AxConfigSchema.parse(opts.configOverride)
123	      : await loadAxConfig({ cwd });
124	
125	  const bus = new HookBus();
126	
127	  const plugins: Plugin[] = [];
128	
129	  // Storage (always sqlite for now; schema gates this).
130	  plugins.push(
131	    createStorageSqlitePlugin({
132	      databasePath: opts.sqlitePath ?? DEFAULT_SQLITE_PATH,
133	    }),
134	  );
135	
136	  // Credentials sits immediately after storage (it calls storage:get/set) and
137	  // before any plugin that resolves `credential_ref`s via credentials:get
138	  // (e.g. @ax/mcp-client lands in Task 16). Bootstrap is topologically
139	  // ordered by declared calls/registers, but pushing in-order keeps the
140	  // intent obvious to readers. Init requires AX_CREDENTIALS_KEY in env.
141	  plugins.push(createCredentialsPlugin());
142	
143	  // Audit log is part of the canary loop.
144	  plugins.push(auditLogPlugin());
145	
146	  // Sandbox. Config only admits 'subprocess' today; the switch is future-
147	  // proofing for when alternate sandbox providers land.
148	  if (cfg.sandbox === 'subprocess') {
149	    plugins.push(createSandboxSubprocessPlugin());
150	  }
151	
152	  // Session + IPC + chat orchestration. Together these replace the old
153	  // in-process `registerChatLoop` — `chat:run` is now registered by
154	  // @ax/chat-orchestrator, which drives the per-chat lifecycle through
155	  // sandbox:open-session + session:queue-work and awaits chat:end from
156	  // the runner (delivered by @ax/ipc-server).
157	  plugins.push(createSessionInmemoryPlugin());
158	  plugins.push(createIpcServerPlugin());
159	  plugins.push(createLlmProxyAnthropicFormatPlugin());
160	  plugins.push(
161	    createChatOrchestratorPlugin({
162	      runnerBinary: resolveRunnerBinary(cfg.runner),
163	      chatTimeoutMs: DEFAULT_CHAT_TIMEOUT_MS,
164	    }),
165	  );
166	
167	  // Tool dispatcher is the single entry point for `tool:execute`, fanning
168	  // out to whatever tool plugins register descriptors. Always present when
169	  // we might have tools. (After Task 7, bash/file-io here are descriptor-
170	  // only — actual execution runs in the sandbox via the impl packages.)
171	  plugins.push(createToolDispatcherPlugin());
172	  if (cfg.tools.includes('bash')) {
