1	// ax-next serve --port <n>
2	//
3	// Boots the k8s preset (postgres trio + workspace + sandbox-k8s + chat
4	// orchestrator + ipc-http + tools + LLM) and exposes a thin HTTP front door:
5	//
6	//   GET  /health  → 200 OK (no auth) — for k8s readiness/liveness probes.
7	//   POST /chat    → mints a session, runs one chat turn, returns the outcome.
8	//
9	// We deliberately keep the HTTP surface tiny. The full multi-tenant story
10	// (real auth, per-user sessions, agents, admin UI) is Week 9.5's territory;
11	// this command exists to make the chart's host pod actually boot and to
12	// satisfy the multi-replica MANUAL-ACCEPTANCE scenario.
13	//
14	// Auth: optional bearer token via AX_SERVE_TOKEN. If unset, /chat is open to
15	// anything that can route to this port. We log a loud warning at boot so an
16	// operator can't accidentally ship that posture to production thinking it
17	// was protected. The chart's NetworkPolicy + the fact that ingress is OFF by
18	// default still bounds reach to in-cluster + port-forward.
19	
20	import * as http from 'node:http';
21	import { randomUUID } from 'node:crypto';
22	import {
23	  HookBus,
24	  PluginError,
25	  bootstrap,
26	  makeChatContext,
27	  type ChatMessage,
28	  type ChatOutcome,
29	  type Plugin,
30	} from '@ax/core';
31	import {
32	  createK8sPlugins,
33	  loadK8sConfigFromEnv,
34	} from '@ax/preset-k8s';
35	
36	const DEFAULT_PORT = 8080;
37	const DEFAULT_HOST = '0.0.0.0';
38	// Bound the request body. Chat messages can be long but they're not files —
39	// 1 MiB is more than enough and keeps a misbehaving client from filling
40	// memory. Distinct from @ax/core's MAX_FRAME (4 MiB) because that cap is
41	// for runner ↔ host IPC, where binary tool outputs can be larger.
42	const MAX_BODY_BYTES = 1 * 1024 * 1024;
43	
44	const USAGE = `usage: ax-next serve [--port <n>] [--host <h>]
45	  --port  TCP port to listen on (default ${DEFAULT_PORT})
46	  --host  bind address (default ${DEFAULT_HOST})
47	
48	env (required):
49	  DATABASE_URL              postgres DSN
50	  AX_K8S_HOST_IPC_URL       cluster URL runners use to reach this pod
51	  AX_WORKSPACE_BACKEND      'local' | 'http'
52	  AX_WORKSPACE_ROOT         (when backend=local)
53	  AX_WORKSPACE_GIT_HTTP_URL    (when backend=http)
54	  AX_WORKSPACE_GIT_HTTP_TOKEN  (when backend=http)
55	  ANTHROPIC_API_KEY         used by @ax/llm-anthropic at init
56	  AX_CREDENTIALS_KEY        used by @ax/credentials at init
57	
58	env (optional):
59	  AX_SERVE_TOKEN            if set, /chat requires Bearer <token>
60	                            if unset, /chat is unauthenticated (loud warning)
61	  K8S_NAMESPACE / K8S_POD_IMAGE / K8S_RUNTIME_CLASS / K8S_IMAGE_PULL_SECRETS
62	  BIND_HOST / PORT          (overridden by --host / --port if both present)
63	  AX_LLM_MODEL / AX_LLM_MAX_TOKENS
64	  AX_RUNNER_BINARY / AX_CHAT_TIMEOUT_MS`;
65	
66	interface ParsedArgs {
67	  port: number;
68	  host: string;
69	}
70	
71	function parseArgs(argv: string[]): ParsedArgs | { error: string } {
72	  let port = DEFAULT_PORT;
73	  let host = DEFAULT_HOST;
74	  for (let i = 0; i < argv.length; i++) {
75	    const a = argv[i]!;
76	    if (a === '--port') {
77	      const v = argv[i + 1];
78	      if (v === undefined) return { error: '--port requires a value' };
79	      const n = Number(v);
80	      // Allow 0 ("OS-assigned port" — tests rely on it). Reject negative
81	      // and >65535. Non-integer values (e.g. NaN) fail the Finite check.
82	      if (!Number.isFinite(n) || n < 0 || n > 65535 || !Number.isInteger(n)) {
83	        return { error: `--port must be 0..65535, got ${v}` };
84	      }
85	      port = n;
86	      i++;
87	    } else if (a === '--host') {
88	      const v = argv[i + 1];
89	      if (v === undefined) return { error: '--host requires a value' };
90	      host = v;
91	      i++;
92	    } else if (a === '--help' || a === '-h') {
93	      return { error: 'help' };
94	    } else {
95	      return { error: `unknown argument: ${a}` };
96	    }
97	  }
98	  return { port, host };
99	}
100	
101	export interface RunServeOptions {
102	  argv: string[];
103	  /** Defaults to `process.env`. Tests pass an explicit map. */
104	  env?: NodeJS.ProcessEnv;
105	  stdout?: (line: string) => void;
106	  stderr?: (line: string) => void;
107	  /**
108	   * Test-only seam. When set, skips `loadK8sConfigFromEnv` + `createK8sPlugins`
109	   * and uses the returned plugins instead. Production callers don't pass this
110	   * — they rely on the env-driven preset.
111	   */
112	  pluginsFactory?: (env: NodeJS.ProcessEnv) => Plugin[] | Promise<Plugin[]>;
113	  /**
114	   * Test-only seam. When provided, called with the bound listener so tests
115	   * can read back the actual port and tear down. Production lifecycle is
116	   * SIGTERM-driven; this hook is never invoked there.
117	   */
118	  onListening?: (handle: { host: string; port: number; close: () => Promise<void> }) => void;
119	}
120	
121	export async function runServeCommand(opts: RunServeOptions): Promise<number> {
122	  const out = opts.stdout ?? ((line: string) => process.stdout.write(line + '\n'));
123	  const err = opts.stderr ?? ((line: string) => process.stderr.write(line + '\n'));
124	  const env = opts.env ?? process.env;
125	
126	  const parsed = parseArgs(opts.argv);
127	  if ('error' in parsed) {
128	    if (parsed.error === 'help') {
129	      out(USAGE);
130	      return 0;
131	    }
132	    err(`serve: ${parsed.error}`);
133	    err(USAGE);
134	    return 2;
135	  }
136	
137	  // Loud warning when running unauthenticated. We boot anyway because the
138	  // local-dev / kind canary path legitimately runs without a token; an
139	  // operator targeting prod still has the chart's NetworkPolicy + ingress-off
140	  // posture as defense in depth.
141	  const serveToken = env.AX_SERVE_TOKEN;
142	  if (serveToken === undefined || serveToken === '') {
143	    err('serve: AX_SERVE_TOKEN is unset — /chat is open to anything that can reach this port');
144	  }
145	
146	  // Production-only: register signal handlers BEFORE the heavy boot work
147	  // (preset bootstrap + listen). If kubelet sends SIGTERM during a slow
148	  // boot (postgres pool warm-up, k8s API client init, image-pull races),
149	  // Node's default SIGTERM handler terminates immediately and skips any
150	  // partial cleanup. Registering handlers up-front + gating on a
151	  // `closeListener` reference keeps SIGTERM-during-boot fast and SIGTERM-
152	  // after-boot graceful. Tests pass `onListening`, which we treat as a
153	  // signal that the test owns teardown.
154	  let closeListener: (() => Promise<void>) | null = null;
155	  const isTest = opts.onListening !== undefined;
156	  if (!isTest) {
157	    let shuttingDown = false;
158	    const shutdown = async (sig: NodeJS.Signals): Promise<void> => {
159	      if (shuttingDown) return;
160	      shuttingDown = true;
161	      err(`[ax/serve] ${sig} — closing listener`);
162	      if (closeListener === null) {
163	        // Signal landed mid-boot; nothing to drain.
164	        process.exit(0);
165	      }
166	      try {
167	        await closeListener();
168	        process.exit(0);
169	      } catch (e) {
170	        err(`[ax/serve] shutdown error: ${e instanceof Error ? e.message : String(e)}`);
171	        process.exit(1);
172	      }
173	    };
174	    process.on('SIGTERM', () => void shutdown('SIGTERM'));
175	    process.on('SIGINT', () => void shutdown('SIGINT'));
176	  }
177	
178	  // Build the plugin list. Production: env → K8sPresetConfig → createK8sPlugins.
179	  // Tests: caller-provided.
180	  let plugins: Plugin[];
181	  if (opts.pluginsFactory !== undefined) {
182	    plugins = await opts.pluginsFactory(env);
183	  } else {
184	    let cfg;
185	    try {
186	      cfg = loadK8sConfigFromEnv(env);
187	    } catch (e) {
188	      err(`serve: ${e instanceof Error ? e.message : String(e)}`);
189	      return 2;
190	    }
191	    plugins = createK8sPlugins(cfg);
192	  }
193	
194	  const bus = new HookBus();
195	  await bootstrap({ bus, plugins, config: {} });
196	
197	  const server = http.createServer((req, res) => {
198	    void handle(req, res, bus, serveToken).catch((e) => {
199	      // Per-request fallback. Should not normally fire — `handle` catches
200	      // its own errors — but a programming bug shouldn't take the process
201	      // down.
202	      err(`serve: unhandled handler error: ${e instanceof Error ? e.message : String(e)}`);
203	      try {
204	        if (!res.headersSent) writeJson(res, 500, { error: { code: 'INTERNAL', message: 'internal server error' } });
205	        else res.end();
206	      } catch {
207	        // socket already dead
208	      }
209	    });
210	  });
211	
212	  await new Promise<void>((resolve, reject) => {
213	    const onErr = (e: Error): void => reject(e);
214	    server.once('error', onErr);
215	    server.listen(parsed.port, parsed.host, () => {
216	      server.off('error', onErr);
217	      resolve();
218	    });
219	  });
220	
221	  // Permanent error handler so a stray server-level error doesn't crash us.
222	  server.on('error', (e) => {
223	    err(`serve: server error: ${e instanceof Error ? e.message : String(e)}`);
224	  });
225	
226	  const addr = server.address();
227	  const boundPort = typeof addr === 'object' && addr !== null ? addr.port : parsed.port;
228	  out(`[ax/serve] listening on http://${parsed.host}:${boundPort}`);
229	
230	  const close = async (): Promise<void> => {
231	    await new Promise<void>((resolve) => server.close(() => resolve()));
232	  };
233	
234	  if (opts.onListening !== undefined) {
235	    opts.onListening({ host: parsed.host, port: boundPort, close });
236	    // Tests own teardown; signal handlers were not installed.
237	    return 0;
238	  }
239	
240	  // Production: hand the close handle to the pre-installed signal
241	  // handlers, then block forever.
242	  closeListener = close;
243	  return new Promise<number>(() => {
244	    // never resolves; signal handlers above own exit
245	  });
246	}
247	
248	// ---------------------------------------------------------------------------
249	// HTTP handler
250	// ---------------------------------------------------------------------------
251	
252	async function handle(
253	  req: http.IncomingMessage,
254	  res: http.ServerResponse,
255	  bus: HookBus,
256	  serveToken: string | undefined,
257	): Promise<void> {
258	  // Method gate
259	  if (req.method !== 'GET' && req.method !== 'POST') {
260	    return writeJson(res, 405, { error: { code: 'VALIDATION', message: 'method not allowed' } });
261	  }
262	
263	  const url = new URL(req.url ?? '/', 'http://serve.local');
264	  const pathname = url.pathname;
265	
266	  // /health pre-auth — k8s probes hit this. Always 200 unconditionally.
267	  if (pathname === '/health' && req.method === 'GET') {
268	    writeJson(res, 200, { ok: true });
269	    return;
270	  }
271	
272	  // Auth: when serveToken is set, /chat requires Bearer <token>.
273	  if (serveToken !== undefined && serveToken !== '') {
274	    const auth = req.headers.authorization ?? '';
275	    const expected = `Bearer ${serveToken}`;
276	    // Constant-time-ish: same length + .toLowerCase() doesn't help us here
277	    // since the token portion is case-sensitive. We do a length-pre-check
278	    // and string compare. A stricter timingSafeEqual would also be fine; the
279	    // token never appears in any error message either way.
280	    if (auth.length !== expected.length || auth !== expected) {
281	      return writeJson(res, 401, { error: { code: 'UNAUTHORIZED', message: 'invalid or missing bearer token' } });
282	    }
283	  }
284	
285	  // /chat — POST JSON {message: string, sessionId?: string}.
286	  if (pathname === '/chat' && req.method === 'POST') {
287	    return handleChat(req, res, bus);
288	  }
289	
290	  writeJson(res, 404, { error: { code: 'NOT_FOUND', message: `unknown path: ${pathname}` } });
291	}
292	
293	async function handleChat(
294	  req: http.IncomingMessage,
295	  res: http.ServerResponse,
296	  bus: HookBus,
297	): Promise<void> {
298	  // Content-type
299	  const ct = (req.headers['content-type'] ?? '').toLowerCase();
300	  if (!ct.startsWith('application/json')) {
301	    return writeJson(res, 415, { error: { code: 'VALIDATION', message: 'content-type must be application/json' } });
302	  }
303	
304	  // Body cap
305	  const cl = req.headers['content-length'];
306	  if (typeof cl === 'string' && cl.length > 0) {
307	    const declared = Number(cl);
308	    if (Number.isFinite(declared) && declared > MAX_BODY_BYTES) {
309	      return writeJson(res, 413, { error: { code: 'VALIDATION', message: 'body too large' } });
310	    }
311	  }
312	
313	  // Read body with mid-stream cap.
314	  let body: unknown;
315	  try {
316	    body = await readJsonBodyCapped(req, MAX_BODY_BYTES);
317	  } catch (e) {
318	    if (e instanceof BodyTooLargeError) {
319	      return writeJson(res, 413, { error: { code: 'VALIDATION', message: 'body too large' } });
320	    }
321	    if (e instanceof BadJsonError) {
322	      return writeJson(res, 400, { error: { code: 'VALIDATION', message: `invalid json: ${e.message}` } });
323	    }
324	    throw e;
325	  }
326	
327	  // Validate payload shape.
328	  if (typeof body !== 'object' || body === null) {
329	    return writeJson(res, 400, { error: { code: 'VALIDATION', message: 'body must be a JSON object' } });
330	  }
331	  const message = (body as { message?: unknown }).message;
332	  if (typeof message !== 'string' || message.length === 0) {
333	    return writeJson(res, 400, { error: { code: 'VALIDATION', message: 'message must be a non-empty string' } });
334	  }
335	  const sessionId = (body as { sessionId?: unknown }).sessionId;
336	  if (sessionId !== undefined && (typeof sessionId !== 'string' || sessionId.length === 0)) {
337	    return writeJson(res, 400, { error: { code: 'VALIDATION', message: 'sessionId must be a non-empty string when provided' } });
338	  }
339	
340	  // Always mint a fresh session for each chat. Sharing sessionIds across
341	  // requests is a multi-tenant concern (Week 9.5) — for the canary scenario
342	  // we want each request to be independent.
343	  const finalSessionId = sessionId !== undefined ? (sessionId as string) : `serve-${randomUUID()}`;
344	  const workspaceRoot = '/'; // synthetic — not used for workspace ops in http backend
345	
346	  // session:create. Idempotency-ish: session-postgres throws on duplicate
347	  // sessionId, so a client passing the same sessionId twice will get a 500
348	  // here. Document that for now; multi-turn within one session is Week 9.5.
349	  try {
350	    await bus.call('session:create', makeServeCtx(finalSessionId, workspaceRoot), {
351	      sessionId: finalSessionId,
352	      workspaceRoot,
353	    });
354	  } catch (e) {
355	    if (e instanceof PluginError) {
356	      return writeJson(res, 400, { error: { code: e.code, message: e.message } });
357	    }
358	    throw e;
359	  }
360	
361	  // chat:run.
362	  const ctx = makeServeCtx(finalSessionId, workspaceRoot);
363	  const chatMessage: ChatMessage = { role: 'user', content: message };
364	  let outcome: ChatOutcome;
365	  try {
366	    outcome = await bus.call('chat:run', ctx, { message: chatMessage });
367	  } catch (e) {
368	    if (e instanceof PluginError) {
369	      return writeJson(res, 500, { error: { code: e.code, message: e.message } });
370	    }
371	    return writeJson(res, 500, { error: { code: 'INTERNAL', message: e instanceof Error ? e.message : String(e) } });
372	  }
373	
374	  writeJson(res, 200, { sessionId: finalSessionId, outcome });
375	}
376	
377	function makeServeCtx(sessionId: string, workspaceRoot: string) {
378	  return makeChatContext({
379	    sessionId,
380	    agentId: 'serve',
381	    userId: 'serve',
382	    workspace: { rootPath: workspaceRoot },
383	  });
384	}
385	
386	// ---------------------------------------------------------------------------
387	// Body / response helpers (small enough not to warrant a shared package)
388	// ---------------------------------------------------------------------------
389	
390	class BodyTooLargeError extends Error {
391	  constructor(msg: string) {
392	    super(msg);
393	    this.name = 'BodyTooLargeError';
394	  }
395	}
396	
397	class BadJsonError extends Error {
398	  constructor(msg: string) {
399	    super(msg);
400	    this.name = 'BadJsonError';
401	  }
402	}
403	
404	function readJsonBodyCapped(req: http.IncomingMessage, maxBytes: number): Promise<unknown> {
405	  return new Promise<unknown>((resolve, reject) => {
406	    const chunks: Buffer[] = [];
407	    let total = 0;
408	    let settled = false;
409	    const settle = (fn: () => void): void => {
410	      if (settled) return;
411	      settled = true;
412	      fn();
413	    };
414	    req.on('data', (chunk: Buffer) => {
415	      if (settled) return;
416	      total += chunk.length;
417	      if (total > maxBytes) {
418	        req.destroy();
419	        settle(() => reject(new BodyTooLargeError(`body exceeded cap ${maxBytes}`)));
420	        return;
421	      }
422	      chunks.push(chunk);
423	    });
424	    req.on('error', (e) => settle(() => reject(e)));
425	    req.on('end', () => {
426	      if (settled) return;
427	      try {
428	        const value = JSON.parse(Buffer.concat(chunks, total).toString('utf8'));
429	        settle(() => resolve(value));
430	      } catch (e) {
431	        settle(() => reject(new BadJsonError((e as Error).message)));
432	      }
433	    });
434	  });
435	}
436	
437	function writeJson(res: http.ServerResponse, status: number, body: unknown): void {
438	  res.writeHead(status, { 'Content-Type': 'application/json' });
439	  res.end(JSON.stringify(body));
440	}
