1	// ---------------------------------------------------------------------------
2	// Host-side plugin for @ax/workspace-git-http.
3	//
4	// Registers the four `workspace:*` service hooks against an HTTP client
5	// pointed at the git-server pod. Single responsibility: marshal hook calls
6	// onto the wire, hydrate wire responses back into the lazy WorkspaceDelta
7	// shape that subscribers expect from the in-process backend.
8	//
9	// Two factories:
10	//   - createWorkspaceGitHttpPlugin({baseUrl, token}) — production. Builds
11	//     the HTTP client synchronously inside init().
12	//   - createWorkspaceGitHttpPluginAsync({boot}) — TEST-ONLY. The boot
13	//     callback runs once inside init() and yields {baseUrl, token}. Used by
14	//     the contract test harness so each test scenario can spin up a fresh
15	//     in-process server.
16	//
17	// Invariant I2 (no cross-plugin imports): the host plugin imports from
18	// @ax/core and @ax/workspace-protocol only. Server-side bits (and their
19	// dependency on @ax/workspace-git-core) are isolated to ./server/*.
20	// ---------------------------------------------------------------------------
21	
22	import {
23	  asWorkspaceVersion,
24	  type Bytes,
25	  type HookBus,
26	  type Plugin,
27	  type WorkspaceApplyInput,
28	  type WorkspaceApplyOutput,
29	  type WorkspaceChange,
30	  type WorkspaceDelta,
31	  type WorkspaceDiffInput,
32	  type WorkspaceDiffOutput,
33	  type WorkspaceListInput,
34	  type WorkspaceListOutput,
35	  type WorkspaceReadInput,
36	  type WorkspaceReadOutput,
37	} from '@ax/core';
38	import { base64ToBytes, bytesToBase64 } from '@ax/workspace-protocol';
39	import {
40	  createWorkspaceGitHttpClient,
41	  type WorkspaceGitHttpClient,
42	} from './client.js';
43	
44	const PLUGIN_NAME = '@ax/workspace-git-http';
45	
46	export interface CreateWorkspaceGitHttpPluginOptions {
47	  baseUrl: string;
48	  token: string;
49	}
50	
51	/**
52	 * Multi-replica workspace plugin: forwards every `workspace:*` hook to the
53	 * shared git-server pod over HTTP. Use this when the deployment runs more
54	 * than one host replica that needs to share workspace state. Single-replica
55	 * deployments use `@ax/workspace-git` instead.
56	 */
57	export function createWorkspaceGitHttpPlugin(
58	  opts: CreateWorkspaceGitHttpPluginOptions,
59	): Plugin {
60	  return {
61	    manifest: {
62	      name: PLUGIN_NAME,
63	      version: '0.0.0',
64	      registers: [
65	        'workspace:apply',
66	        'workspace:read',
67	        'workspace:list',
68	        'workspace:diff',
69	      ],
70	      calls: [],
71	      subscribes: [],
72	    },
73	    init({ bus }) {
74	      const client = createWorkspaceGitHttpClient({
75	        baseUrl: opts.baseUrl,
76	        token: opts.token,
77	      });
78	      registerHostHooks(bus, client);
79	    },
80	  };
81	}
82	
83	/**
84	 * @internal Test-only async variant. The `boot` callback runs once per
85	 * `init()` call (i.e., once per harness instance) and yields the connection
86	 * info. The contract test uses this to spin up a fresh in-process server
87	 * per scenario without leaking cross-test version history.
88	 *
89	 * Production callers should use `createWorkspaceGitHttpPlugin` with a
90	 * static baseUrl from config.
91	 */
92	export interface CreateWorkspaceGitHttpPluginAsyncOptions {
93	  boot: () => Promise<{ baseUrl: string; token: string }>;
94	}
95	
96	export function createWorkspaceGitHttpPluginAsync(
97	  opts: CreateWorkspaceGitHttpPluginAsyncOptions,
98	): Plugin {
99	  return {
100	    manifest: {
101	      name: PLUGIN_NAME,
102	      version: '0.0.0',
103	      registers: [
104	        'workspace:apply',
105	        'workspace:read',
106	        'workspace:list',
107	        'workspace:diff',
108	      ],
109	      calls: [],
110	      subscribes: [],
111	    },
112	    async init({ bus }) {
113	      const { baseUrl, token } = await opts.boot();
114	      const client = createWorkspaceGitHttpClient({ baseUrl, token });
115	      registerHostHooks(bus, client);
116	    },
117	  };
118	}
119	
120	// ---------------------------------------------------------------------------
121	// Hook registration (shared between the sync and async factories).
122	// ---------------------------------------------------------------------------
123	function registerHostHooks(bus: HookBus, client: WorkspaceGitHttpClient): void {
124	  bus.registerService<WorkspaceApplyInput, WorkspaceApplyOutput>(
125	    'workspace:apply',
126	    PLUGIN_NAME,
127	    async (_ctx, input) => {
128	      // No host-side empty-turn short-circuit, deliberately. The in-process
129	      // backend can short-circuit safely because it knows the current ref
130	      // (impl.ts:394-403). We don't — the canonical version lives on the
131	      // git-server pod, and another replica may have advanced HEAD between
132	      // our last response and this call. Short-circuiting here would
133	      // (a) skip the parent-CAS check the contract requires (see the
134	      // "parent mismatch raises PluginError" assertion) and (b) hand the
135	      // caller a stale `before === after` against a parent that no longer
136	      // matches the server. The server's own short-circuit kicks in once
137	      // we get there, so the only cost we pay is one round-trip.
138	      const wireRes = await client.apply({
139	        changes: input.changes.map((c) =>
140	          c.kind === 'put'
141	            ? {
142	                path: c.path,
143	                kind: 'put' as const,
144	                contentBase64: bytesToBase64(c.content),
145	              }
146	            : { path: c.path, kind: 'delete' as const },
147	        ),
148	        parent: input.parent === null ? null : (input.parent as string),
149	        ...(input.reason !== undefined ? { reason: input.reason } : {}),
150	      });
151	
152	      return {
153	        version: asWorkspaceVersion(wireRes.version),
154	        delta: hydrateDelta(wireRes.delta),
155	      };
156	    },
157	  );
158	
159	  bus.registerService<WorkspaceReadInput, WorkspaceReadOutput>(
160	    'workspace:read',
161	    PLUGIN_NAME,
162	    async (_ctx, input) => {
163	      const r = await client.read({
164	        path: input.path,
165	        ...(input.version !== undefined
166	          ? { version: input.version as string }
167	          : {}),
168	      });
169	      if (r.found) return { found: true, bytes: base64ToBytes(r.bytesBase64) };
170	      return { found: false };
171	    },
172	  );
173	
174	  bus.registerService<WorkspaceListInput, WorkspaceListOutput>(
175	    'workspace:list',
176	    PLUGIN_NAME,
177	    async (_ctx, input) => {
178	      const r = await client.list({
179	        ...(input.pathGlob !== undefined ? { pathGlob: input.pathGlob } : {}),
180	        ...(input.version !== undefined
181	          ? { version: input.version as string }
182	          : {}),
183	      });
184	      return { paths: r.paths };
185	    },
186	  );
187	
188	  bus.registerService<WorkspaceDiffInput, WorkspaceDiffOutput>(
189	    'workspace:diff',
190	    PLUGIN_NAME,
191	    async (_ctx, input) => {
192	      const r = await client.diff({
193	        from: input.from === null ? null : (input.from as string),
194	        to: input.to as string,
195	      });
196	      return { delta: hydrateDelta(r.delta) };
197	    },
198	  );
199	}
200	
201	// ---------------------------------------------------------------------------
202	// Wire-shape -> WorkspaceDelta hydration.
203	//
204	// Bytes are already in memory once we receive the response (HTTP isn't lazy),
205	// so the closures we wrap them in are trivial Promise.resolve() returns.
206	// The point of laziness here is shape parity with the in-process backend so
207	// subscribers see the same shape regardless of transport — they MUST call
208	// contentBefore()/contentAfter() to get bytes, regardless of which backend
209	// served the hook.
210	// ---------------------------------------------------------------------------
211	
212	// Type alias inferred from the client surface — keeps us in sync with the
213	// wire schema without re-stating it. (Identical structure on apply.delta and
214	// diff.delta since both reuse WireDeltaSchema in @ax/workspace-protocol.)
215	type WireDelta = Awaited<ReturnType<WorkspaceGitHttpClient['apply']>>['delta'];
216	
217	function hydrateDelta(d: WireDelta): WorkspaceDelta {
218	  const changes: WorkspaceChange[] = d.changes.map((c) => {
219	    if (c.kind === 'added') {
220	      const bytes: Bytes = base64ToBytes(c.contentAfterBase64);
221	      return {
222	        path: c.path,
223	        kind: 'added',
224	        contentAfter: () => Promise.resolve(bytes),
225	      };
226	    }
227	    if (c.kind === 'modified') {
228	      const before: Bytes = base64ToBytes(c.contentBeforeBase64);
229	      const after: Bytes = base64ToBytes(c.contentAfterBase64);
230	      return {
231	        path: c.path,
232	        kind: 'modified',
233	        contentBefore: () => Promise.resolve(before),
234	        contentAfter: () => Promise.resolve(after),
235	      };
236	    }
237	    // c.kind === 'deleted'
238	    const before: Bytes = base64ToBytes(c.contentBeforeBase64);
239	    return {
240	      path: c.path,
241	      kind: 'deleted',
242	      contentBefore: () => Promise.resolve(before),
243	    };
244	  });
245	
246	  const out: WorkspaceDelta = {
247	    before: d.before === null ? null : asWorkspaceVersion(d.before),
248	    after: asWorkspaceVersion(d.after),
249	    changes,
250	  };
251	  if (d.reason !== undefined) out.reason = d.reason;
252	  if (d.author !== undefined) out.author = d.author;
253	  return out;
254	}
255

