1	import type { HookBus } from './hook-bus.js';
2	import { PluginError } from './errors.js';
3	import { PluginManifestSchema, type Plugin } from './plugin.js';
4	
5	const DEFAULT_SHUTDOWN_TIMEOUT_MS = 10_000;
6	
7	export interface BootstrapOptions {
8	  bus: HookBus;
9	  plugins: Plugin[];
10	  config: Record<string, unknown>;
11	  /**
12	   * Per-plugin shutdown timeout in milliseconds. Defaults to 10_000 to
13	   * match `IPC_TIMEOUTS_MS` and give slow drains (in-flight queries,
14	   * LISTEN client end, k8s informer cleanup) breathing room without
15	   * unbounded waits. A misbehaving plugin can't hold the process
16	   * hostage past this ceiling.
17	   */
18	  shutdownTimeoutMs?: number;
19	  /**
20	   * Sink for shutdown errors. Invoked once per plugin whose
21	   * `shutdown()` throws or times out. The kernel always logs to
22	   * `process.stderr` if no sink is provided. Hosts that want
23	   * structured logs (e.g., the `serve` binary feeding a JSON logger)
24	   * pass an explicit sink.
25	   *
26	   * Init-failure rollback uses the same sink — that path also calls
27	   * `shutdown()` on already-initialized plugins, and their failures
28	   * deserve the same routing as a normal-shutdown failure.
29	   */
30	  onShutdownError?: (pluginName: string, err: unknown) => void;
31	}
32	
33	/**
34	 * Returned by `bootstrap()`. The host calls `shutdown()` on SIGTERM /
35	 * SIGINT (or whenever the process needs a clean teardown). Idempotent:
36	 * the first call kicks off the shutdown sequence and caches its
37	 * promise; subsequent calls return the cached promise without
38	 * re-running any plugin's `shutdown()`.
39	 *
40	 * The kernel intentionally does NOT install signal handlers — that's
41	 * the host's job. Tests drive `shutdown()` directly; embedded uses
42	 * keep their parent process in charge of signal lifecycle.
43	 */
44	export interface KernelHandle {
45	  shutdown(): Promise<void>;
46	}
47	
48	export async function bootstrap(opts: BootstrapOptions): Promise<KernelHandle> {
49	  const { bus, plugins, config } = opts;
50	  const shutdownTimeoutMs = opts.shutdownTimeoutMs ?? DEFAULT_SHUTDOWN_TIMEOUT_MS;
51	  const onShutdownError =
52	    opts.onShutdownError ??
53	    ((name: string, err: unknown) => {
54	      const msg = err instanceof Error ? err.message : String(err);
55	      process.stderr.write(`kernel: plugin '${name}' shutdown failed: ${msg}\n`);
56	    });
57	
58	  for (const p of plugins) {
59	    const parsed = PluginManifestSchema.safeParse(p.manifest);
60	    if (!parsed.success) {
61	      throw new PluginError({
62	        code: 'invalid-manifest',
63	        plugin: p.manifest?.name ?? 'unknown',
64	        message: `invalid plugin manifest: ${parsed.error.message}`,
65	        cause: parsed.error,
66	      });
67	    }
68	  }
69	
70	  checkDuplicatePluginNames(plugins);
71	  const graph = validateDependencyGraph(plugins);
72	  const order = topologicalOrder(plugins, graph);
73	
74	  // Track which plugins have completed init so a mid-init failure can roll
75	  // back only the prefix that succeeded (I4). The failing plugin itself is
76	  // NOT included — its init didn't complete, so its resources may not
77	  // exist, and calling its shutdown could race or NPE on partial state.
78	  const initialized: Plugin[] = [];
79	  for (const p of order) {
80	    try {
81	      await p.init({ bus, config: config[p.manifest.name] });
82	      initialized.push(p);
83	    } catch (err) {
84	      // Roll back already-initialized plugins under the same per-plugin
85	      // timeout + isolation as normal shutdown.
86	      await runShutdownLoop(initialized, shutdownTimeoutMs, onShutdownError);
87	      if (err instanceof PluginError) throw err;
88	      throw new PluginError({
